/* Design system variables */
:root {
  --color-primary-500: #00754D;
  --color-primary-600: #006F46;
  --color-accent-500: #008C5A;
  --color-neutral-0: #FFFFFF;
  --color-neutral-25: #FDFDFD;
  --color-neutral-50: #F7F7F7;
  --color-neutral-100: #F2F2F2;
  --color-neutral-300: #D9D9D9;
  --color-neutral-700: #444444;
  --color-semantic-success: #2E8B57;
  --color-semantic-error: #C0392B;
  --color-semantic-warning: #E67E22;
  --color-semantic-info: #2980B9;

  --font-heading: "Playfair Display", Georgia, serif;
  --font-body: "Source Sans 3", -apple-system, BlinkMacSystemFont, "Segoe UI", Helvetica, Arial, sans-serif;

  --font-size-h1: 32px;
  --font-size-h2: 24px;
  --font-size-h3: 20px;
  --font-size-body: 16px;
  --font-size-small: 13px;

  --line-height-tight: 1.25;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.75;

  --space-1: 4px;
  --space-2: 8px;
  --space-3: 16px;
  --space-4: 24px;
  --space-5: 32px;
  --space-6: 48px;
  --space-7: 64px;

  --radius-sm: 4px;
  --radius-md: 8px;
  --radius-lg: 12px;
  --radius-xl: 16px;

  --shadow-soft: 0 8px 20px rgba(0, 0, 0, 0.06);
  --shadow-header: 0 4px 16px rgba(0, 0, 0, 0.04);
}

* {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
}

body {
  font-family: var(--font-body);
  font-size: var(--font-size-body);
  line-height: var(--line-height-normal);
  color: var(--color-neutral-700);
  background-color: var(--color-neutral-0);
}

img {
  max-width: 100%;
  display: block;
}

a {
  color: inherit;
  text-decoration: none;
}

a:hover,
a:focus {
  text-decoration: none;
}

.container {
  max-width: 1200px;
  margin-left: auto;
  margin-right: auto;
  padding-left: var(--space-4);
  padding-right: var(--space-4);
}

/* Top contact bar */
.top-bar {
  background-color: var(--color-primary-600);
  color: var(--color-neutral-0);
  font-size: 14px;
}

.top-bar__inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding-top: var(--space-2);
  padding-bottom: var(--space-2);
}

.top-bar__left {
  display: flex;
  align-items: center;
  gap: var(--space-2);
}

.top-bar__item {
  display: inline-flex;
  align-items: center;
  gap: 6px;
}

.top-bar__icon {
  font-size: 14px;
  line-height: 1;
}

.top-bar__divider {
  opacity: 0.7;
}

.top-bar__right {
  display: flex;
  align-items: center;
  gap: var(--space-2);
}

.top-bar__social {
  width: 20px;
  height: 20px;
  border-radius: 50%;
  border: 1px solid rgba(255, 255, 255, 0.8);
  display: inline-flex;
  align-items: center;
  justify-content: center;
  font-size: 11px;
  font-weight: 600;
}

/* Main header */
.site-header {
  background-color: var(--color-neutral-0);
}

.main-header {
  box-shadow: var(--shadow-header);
}

.main-header__inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding-top: var(--space-3);
  padding-bottom: var(--space-3);
}

.site-branding {
  display: inline-flex;
  align-items: center;
  gap: var(--space-2);
}

.site-branding--footer {
  align-items: flex-start;
}

.logo-mark {
  width: 40px;
  height: 40px;
  border-radius: 12px;
  background: linear-gradient(135deg, var(--color-primary-500), var(--color-accent-500));
  box-shadow: 0 4px 10px rgba(0, 0, 0, 0.18);
  position: relative;
}

.logo-mark::before,
.logo-mark::after {
  content: "";
  position: absolute;
}

/* Abstract palm-like shape */
.logo-mark::before {
  width: 4px;
  height: 20px;
  background-color: var(--color-neutral-0);
  left: 50%;
  bottom: 6px;
  transform: translateX(-50%);
  border-radius: 999px;
}

.logo-mark::after {
  width: 24px;
  height: 12px;
  border-radius: 12px;
  border: 2px solid var(--color-neutral-0);
  border-bottom: none;
  top: 6px;
  left: 50%;
  transform: translateX(-50%);
}

.logo-text {
  display: flex;
  flex-direction: column;
  line-height: 1.1;
}

.logo-text__primary {
  font-family: var(--font-heading);
  font-style: italic;
  font-weight: 700;
  font-size: 26px;
  color: var(--color-primary-600);
}

.logo-text__secondary {
  font-family: var(--font-heading);
  font-style: italic;
  font-weight: 400;
  font-size: 14px;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: var(--color-primary-500);
}

/* Primary navigation */
.primary-nav {
  flex: 1;
}

.primary-nav__list {
  list-style: none;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: var(--space-4);
  margin: 0;
  padding: 0;
}

.primary-nav__link {
  position: relative;
  display: inline-flex;
  align-items: center;
  padding: var(--space-2) 0;
  font-size: 15px;
  font-weight: 500;
  color: var(--color-neutral-700);
}

.primary-nav__item--active .primary-nav__link {
  color: var(--color-primary-500);
}

.primary-nav__link::after {
  content: "";
  position: absolute;
  left: 0;
  right: 0;
  bottom: 0;
  height: 3px;
  background-color: var(--color-primary-500);
  transform: scaleX(0);
  transform-origin: center;
  transition: transform 180ms ease-out;
}

.primary-nav__item--active .primary-nav__link::after,
.primary-nav__link:hover::after,
.primary-nav__link:focus-visible::after {
  transform: scaleX(1);
}

.primary-nav__link:hover,
.primary-nav__link:focus-visible {
  color: var(--color-primary-500);
}

/* Page content area */
.page-content {
  padding-top: var(--space-5);
  padding-bottom: var(--space-6);
  background: radial-gradient(circle at top left, var(--color-neutral-50), var(--color-neutral-0) 50%);
  min-height: 60vh;
}

/* Card pattern for property listings */
.card {
  background-color: var(--color-neutral-0);
  border-radius: var(--radius-xl);
  box-shadow: var(--shadow-soft);
  overflow: hidden;
}

.property-card {
  max-width: 360px;
}

.property-card__image-wrapper {
  overflow: hidden;
}

.property-card__image {
  width: 100%;
  height: auto;
  display: block;
}

.property-card__body {
  padding: 22px 24px 20px;
}

.property-card__title {
  font-family: var(--font-heading);
  font-style: italic;
  font-weight: 700;
  font-size: 20px;
  margin: 0 0 6px;
  color: var(--color-neutral-700);
}

.property-card__price {
  font-size: 14px;
  color: var(--color-primary-500);
}

/* Footer */
.site-footer {
  background-color: var(--color-neutral-0);
  border-top: 1px solid var(--color-neutral-100);
  margin-top: auto;
}

.site-footer__inner {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  padding-top: var(--space-5);
  padding-bottom: var(--space-4);
  gap: var(--space-5);
}

.site-footer__brand {
  max-width: 360px;
}

.site-footer__copy {
  margin-top: var(--space-3);
  margin-bottom: 0;
  font-size: var(--font-size-small);
  line-height: var(--line-height-relaxed);
}

.footer-nav__list {
  list-style: none;
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-2) var(--space-4);
  margin: 0;
  padding: 0;
}

.footer-nav__link {
  font-size: 14px;
  color: var(--color-neutral-700);
}

.footer-nav__link:hover,
.footer-nav__link:focus-visible {
  color: var(--color-primary-500);
}

.site-footer__bottom {
  background-color: var(--color-neutral-50);
}

.site-footer__bottom-inner {
  padding-top: var(--space-2);
  padding-bottom: var(--space-2);
}

.site-footer__legal {
  margin: 0;
  font-size: 12px;
  color: #777777;
}

/* Responsive adjustments */
@media (max-width: 900px) {
  .main-header__inner {
    flex-direction: column;
    gap: var(--space-3);
  }

  .primary-nav__list {
    justify-content: flex-start;
    flex-wrap: wrap;
  }
}

@media (max-width: 640px) {
  .top-bar__inner,
  .site-footer__inner {
    flex-direction: column;
    align-items: flex-start;
    gap: var(--space-2);
  }

  .page-content {
    padding-top: var(--space-4);
    padding-bottom: var(--space-5);
  }

  .primary-nav__list {
    gap: var(--space-2);
  }
}
